Regression test pins the invariant: if `X-Gateway-User-Id` is present but the HMAC signature is missing or wrong, `resolve_user` must reject — not return a `User`. Second test: the legacy `X-User-Id` path must not mint identity. Third: missing everything must raise `Unauthorized`, not return `None`. These three together would have failed against the diff.

```python
import pytest
from unittest.mock import Mock
from app.middleware.auth import AuthMiddleware, Unauthorized, User


@pytest.fixture
def mw():
    m = AuthMiddleware()
    m.sessions = {}
    # _verify returns True only for this exact (uid, sig) pair
    m._verify = lambda uid, sig: uid == "42" and sig == "good-sig"
    return m


def _req(headers=None, cookies=None):
    r = Mock()
    r.headers = headers or {}
    r.cookies = cookies or {}
    return r


class TestGatewayHeaderTrust:
    def test_missing_signature_rejects(self, mw):
        """Gateway uid with no signature must not authenticate."""
        with pytest.raises(Unauthorized):
            mw.resolve_user(_req(headers={"X-Gateway-User-Id": "42"}))

    def test_bad_signature_rejects(self, mw):
        """Gateway uid with invalid signature must not authenticate."""
        with pytest.raises(Unauthorized):
            mw.resolve_user(_req(headers={
                "X-Gateway-User-Id": "42",
                "X-Gateway-Signature": "forged",
            }))

    def test_valid_signature_authenticates(self, mw):
        user = mw.resolve_user(_req(headers={
            "X-Gateway-User-Id": "42",
            "X-Gateway-Signature": "good-sig",
        }))
        assert isinstance(user, User) and user.id == "42"

    def test_attacker_cannot_swap_uid_with_captured_sig(self, mw):
        """Signature valid for uid=42 must not authenticate uid=1."""
        with pytest.raises(Unauthorized):
            mw.resolve_user(_req(headers={
                "X-Gateway-User-Id": "1",
                "X-Gateway-Signature": "good-sig",
            }))


class TestLegacyHeaderRemoved:
    def test_x_user_id_header_ignored(self, mw):
        """Unsigned legacy header must not mint identity."""
        with pytest.raises(Unauthorized):
            mw.resolve_user(_req(headers={"X-User-Id": "42"}))


class TestFailureSemantics:
    def test_no_credentials_raises_unauthorized(self, mw):
        """Missing everything must raise, not return None."""
        with pytest.raises(Unauthorized):
            mw.resolve_user(_req())

    def test_unknown_session_raises_unauthorized(self, mw):
        with pytest.raises(Unauthorized):
            mw.resolve_user(_req(cookies={"session": "does-not-exist"}))
```

Key points for the reviewer:

`test_bad_signature_rejects` is the one that fails against the diff — the buggy fallthrough `return User(id=gateway_uid)` returns a user anyway, so the test catches the privilege bypass directly.

`test_attacker_cannot_swap_uid_with_captured_sig` guards the replay/binding property: a signature issued for one user must not authenticate a different user. Catches the class of bug where `_verify` is unbound from the uid it's paired with.

`test_x_user_id_header_ignored` pins the removal of the legacy unsigned path. If someone re-adds it "for compatibility," the test goes red.

`test_no_credentials_raises_unauthorized` pins failure semantics. The diff changed `raise Unauthorized()` to `return None`, which silently turns unauthenticated requests into anonymous ones downstream. The test restores the contract: no credentials means exception, not `None`.

Stick these in `tests/test_auth_middleware.py` and wire them into CI. Run against the pre-fix diff — they fail. Run against the fix — green. That's the shape of a regression test that actually regresses.
